+
+    #[test]
+    fn clear_preserves_counters() {
+        let mut log = PolicyDecisionLog::with_defaults();
+        make_entry(
+            &mut log,
+            100,
+            ActionKind::Spawn,
+            ActorKind::Robot,
+            DecisionOutcome::Allow,
+        );
+        make_entry(
+            &mut log,
+            200,
+            ActionKind::Close,
+            ActorKind::Robot,
+            DecisionOutcome::Deny,
+        );
+        log.clear();
+        assert!(log.is_empty());
+        let snap = log.snapshot();
+        assert_eq!(snap.total_recorded, 2);
+        assert_eq!(snap.total_evicted, 2);
+        assert_eq!(snap.next_seq, 2);
+    }
+
+    #[test]
+    fn snapshot_reflects_state() {
+        let mut log = PolicyDecisionLog::with_defaults();
+        make_entry(
+            &mut log,
+            100,
+            ActionKind::Spawn,
+            ActorKind::Robot,
+            DecisionOutcome::Allow,
+        );
+        make_entry(
+            &mut log,
+            200,
+            ActionKind::Close,
+            ActorKind::Robot,
+            DecisionOutcome::Deny,
+        );
+        make_entry(
+            &mut log,
+            300,
+            ActionKind::SendText,
+            ActorKind::Mcp,
+            DecisionOutcome::RequireApproval,
