+        assert_eq!(
+            DecisionOutcome::from(DslDecision::Deny),
+            DecisionOutcome::Deny
+        );
+        assert_eq!(
+            DecisionOutcome::from(DslDecision::RequireApproval),
+            DecisionOutcome::RequireApproval
