+    }
+
+    #[test]
+    fn entry_serde_roundtrip() {
+        let entry = PolicyDecisionEntry {
+            seq: 42,
+            timestamp_ms: 1234567890,
+            action: ActionKind::Spawn,
+            actor: ActorKind::Robot,
+            surface: PolicySurface::Mux,
+            pane_id: Some(99),
