+        let json = serde_json::to_string(&entry).unwrap();
+        let back: PolicyDecisionEntry = serde_json::from_str(&json).unwrap();
+        assert_eq!(entry, back);
+    }
+
+    #[test]
+    fn config_serde_roundtrip() {
+        let config = DecisionLogConfig {
+            max_entries: 5000,
+            record_allows: false,
