+
+    #[test]
+    fn snapshot_serde_roundtrip() {
+        let snap = DecisionLogSnapshot {
+            current_entries: 42,
+            max_entries: 10000,
+            total_recorded: 100,
+            total_evicted: 58,
+            next_seq: 100,
+            deny_count: 20,
