+            require_approval_count: 10,
+            record_allows: true,
+        };
+        let json = serde_json::to_string(&snap).unwrap();
+        let back: DecisionLogSnapshot = serde_json::from_str(&json).unwrap();
+        assert_eq!(snap, back);
+    }
