+fn arb_decision_log_snapshot() -> impl Strategy<Value = DecisionLogSnapshot> {
+    (
+        any::<usize>(),
+        any::<usize>(),
+        any::<u64>(),
+        any::<u64>(),
+        any::<u64>(),
+        any::<u64>(),
+        any::<u64>(),
+        any::<u64>(),
+        any::<bool>(),
+    )
+        .prop_map(
+            |(cur, max, recorded, evicted, next, deny, allow, req, rec_allows)| {
+                DecisionLogSnapshot {
+                    current_entries: cur,
+                    max_entries: max,
+                    total_recorded: recorded,
+                    total_evicted: evicted,
+                    next_seq: next,
+                    deny_count: deny,
+                    allow_count: allow,
